const BASE_TALENT_DEFINITIONS = [
  { id: "air-of-authority", name: "Air of Authority", prerequisites: "Fellowship 30", benefit: "On a successful Command test, affect 1d10 plus Fellowship Bonus targets instead of the normal amount.", description: "The Explorer was born to command, either motivating or terrifying those under his charge. On a successful Command Test, the Explorer may affect a number of targets equal to 1d10 plus his Fellowship Bonus. This talent has no effect on hostile targets, and only affects NPCs.", category: "talent" },
  { id: "ambidextrous", name: "Ambidextrous", prerequisites: "Agility 30", benefit: "Ignore the normal off-hand penalty, and reduce two-weapon penalties further when combined with Two-Weapon Wielder.", description: "This Talent does not represent true ambidexterity so much as sufficient training with both hands to make the distinction moot. The Explorer can use either hand equally well for any task, and does not suffer the -20 penalty for actions using his off hand. When combined with a Two-Weapon Wielder Talent, the penalty for making attacks with both weapons in the same Turn drops to -10.", category: "talent" },
  { id: "armour-of-contempt", name: "Armour of Contempt", prerequisites: "Willpower 40", benefit: "Reduce Corruption gained by 1 and briefly ignore Corruption effects with a successful Willpower test.", description: "The Explorer's hatred of all the impure armours his soul against malign influence. Whenever the Explorer gains Corruption Points, reduce the total by 1, to a minimum of 0. With a successful Willpower Test, taken as a Free Action, he may ignore the effects of accumulated Corruption Points for 1 Round.", category: "talent" },
  { id: "assassin-strike", name: "Assassin Strike", prerequisites: "Agility 40, Acrobatics", benefit: "After a melee attack, make an Acrobatics test to move half your rate as a Free Action without provoking free attacks.", description: "The Explorer's natural agility and graceful martial forms turn him into a dervish of death on the battlefield. After making a melee attack, a successful Acrobatics Test allows him to move at half rate as a Free Action. The Explorer's opponent does not receive a free attack resulting from this move. He may only take this additional move once per Round.", category: "talent" },
  { id: "autosanguine", name: "Autosanguine", prerequisites: "", benefit: "Always count as Lightly Wounded for healing and recover 2 Damage per day.", description: "The ancient and blessed technology of the Mechanicus or some corrupt xeno tech flows through the Explorer's blood. These miniscule machines repair minor injuries and speed healing. When applying healing, he is always considered Lightly Wounded, and heals at an increased rate, removing 2 points of Damage per day.", category: "talent" },
  { id: "basic-weapon-training", name: "Basic Weapon Training", prerequisites: "", benefit: "Use the chosen group of basic weapons without the untrained penalty.", description: "The Explorer has received Basic Weapon Training in a group of weapons, and can use them without penalty. The Universal group includes the Bolt, Las, Launcher, Melta, Plasma, and SP groups. When a character attempts to use a weapon he does not have the correct Weapon Training Talent for, he suffers a -20 penalty to any relevant Weapon Skill or Ballistic Skill Test.", category: "talent", groupKey: "basicWeaponTraining" },
  { id: "bastion-of-iron-will", name: "Bastion of Iron Will", prerequisites: "Psy Rating, Strong Minded, Willpower 40", benefit: "Double your defensive Psy Rating on opposed Psyniscience and Psychic Technique tests.", description: "The Explorer's sheer willpower and psychic focus have become one and the same over years of practice and training, such that their combined use is second nature. He doubles his defensive Psy Rating on any Opposed Test involving the Psyniscience Skill or Psychic Techniques.", category: "talent" },
  { id: "battle-rage", name: "Battle Rage", prerequisites: "Frenzy", benefit: "You may Parry while Frenzied.", description: "Long experience and indomitable will have allowed the Explorer to master the beast within, directing its rage while keeping a level head. He can Parry while Frenzied.", category: "talent" },
  { id: "berserk-charge", name: "Berserk Charge", prerequisites: "", benefit: "Gain +20 Weapon Skill on a Charge instead of +10.", description: "The Explorer has learned to put the whole force of his momentum behind his weapon blows. When he uses the Charge Action, he gains a +20 bonus to Weapon Skill instead of +10.", category: "talent" },
  { id: "binary-chatter", name: "Binary Chatter", prerequisites: "", benefit: "Gain +10 to communicate with servitors, and your vessel gains +1 Crew Morale from greater servitor efficiency.", description: "The Explorer has optimised his use of Techna-Lingua for controlling servitors. He receives a +10 bonus to any attempt to communicate with servitors, and any vessel upon which he serves receives a +1 bonus to Crew Morale due to increased servitor efficiency.", category: "talent" },
  { id: "blademaster", name: "Blademaster", prerequisites: "Weapon Skill 30, Melee Weapon Training", benefit: "With bladed weapons, re-roll one missed attack per Round.", description: "The Explorer's mastery of bladed weapons and their martial disciplines has no peer. When attacking with any bladed weapon, including chain weapons, power axes, and power swords, he may re-roll one missed attack per Round.", category: "talent" },
  { id: "blessed-radiance", name: "Blessed Radiance", prerequisites: "Purge the Unclean, Divine Ministration, The Emperor Protects, or Wrath of the Righteous", benefit: "Your Pure Faith effects can extend to allies, lend Fate temporarily, and grant broad protection when burning Fate.", description: "The Explorer's holiness shines out, allowing all to see the truth of their own souls. When spending a Fate Point to activate the Pure Faith Talent, the Explorer extends the immunity to daemonic presence to a number of targets equal to twice his Willpower Bonus. As a Free Action, he may bestow a single Fate Point to an ally; if the Fate Point is unspent, it returns at the end of the encounter. Upon burning a Fate Point, the Explorer and a number of allies equal to twice his Willpower Bonus become immune to daemonic presence, Fear Tests, and Corruption Points, gain a +10 bonus on Tests to resist psychic attack or manipulation, and take only half Damage from psychic and warp sources for the duration of the encounter.", category: "talent" },
  { id: "blind-fighting", name: "Blind Fighting", prerequisites: "Perception 30", benefit: "Halve penalties caused by obscured vision in close combat.", description: "Years of practice and development of the Explorer's other senses allows him to fight in close combat without the benefit of sight. This Talent reduces all penalties for obscured vision by half, permitting the character to fight in fog, smoke, or darkness.", category: "talent" },
  { id: "bloodtracker", name: "Bloodtracker", prerequisites: "", benefit: "Gain +100 Objective Points toward Military or Criminal Objectives when turning in a fugitive for bounty.", description: "The Explorer is an experienced and cunning bounty hunter who commands the highest price for bringing in a quarry dead or alive. When turning in a fugitive for bounty, the character's group gains a bonus of +100 Objective Points towards Military or Criminal Objectives.", category: "talent" },
  { id: "bulging-biceps", name: "Bulging Biceps", prerequisites: "Strength 45", benefit: "Fire heavy weapons on Semi- or Full Auto without bracing and ignore the usual -30 penalty.", description: "Whereas a weaker man would be sent flying when using powerful weapons, the Explorer's strong physique allows him to remain standing. He can fire heavy weapons using Semi-Auto Burst or Full Auto Burst without bracing, and he does not suffer the -30 penalty for failing to brace.", category: "talent" },
  { id: "catfall", name: "Catfall", prerequisites: "Agility 30", benefit: "On a successful Agility test when falling, reduce effective falling distance by your Agility Bonus per Degree of Success.", description: "Gymnastic ability and natural balance enables the Explorer to fall far greater distances without harm than the common man. Whenever he falls, he may take an Agility Test as a Free Action. Success, and each additional Degree of Success, reduces the distance fallen by a number of metres equal to the character's Agility Bonus for the purposes of determining Damage from the fall.", category: "talent" },
  { id: "chem-geld", name: "Chem Geld", prerequisites: "", benefit: "Seduction attempts automatically fail against you, Charm becomes harder, and you gain 1 Insanity Point.", description: "Either chemical and surgical treatments or sheer will has rendered the Explorer immune to most mundane temptations. Seduction attempts against him automatically fail, and Charm Tests increase their Difficulty by one level. Taking this Talent causes one Insanity Point.", category: "talent" },
  { id: "cleanse-and-purify", name: "Cleanse and Purify", prerequisites: "Flame Weapon Training (Universal)", benefit: "Targets of your flamer attacks take -20 on Agility tests to escape the flames.", description: "The Explorer can control the flow of molten promethium like no other, manipulating flame like an old accomplice. The targets of his flamer attacks take a -20 penalty to their Agility Tests to escape its effects.", category: "talent" },
  { id: "combat-formation", name: "Combat Formation", prerequisites: "Intelligence 40", benefit: "Before initiative is rolled, allies may use your Intelligence Bonus for initiative instead of their Agility Bonuses.", description: "The Explorer has directed his comrades to be prepared for danger, planning out their actions for many contingencies if attacked. Before rolling Initiative, all other members of the group may choose to use the character's Intelligence Bonus for all Initiative rolls rather than individual Agility Bonuses.", category: "talent" },
  { id: "combat-master", name: "Combat Master", prerequisites: "Weapon Skill 30", benefit: "Enemies gain no outnumbering bonuses against you in melee.", description: "The Explorer's weapon seems to be everywhere at once, keeping many more opponents at bay in close combat than even skilled fighters. Opponents gain no bonuses for outnumbering the character in hand-to-hand combat.", category: "talent" },
  { id: "combat-sense", name: "Combat Sense", prerequisites: "Perception 40", benefit: "Use your Perception Bonus instead of Agility Bonus for Initiative.", description: "The Explorer has the ability to consciously recognise the proddings of his subconscious as it reacts to his preternaturally sharp senses, giving him an edge that mere speed cannot match. He can use his Perception Bonus in place of his Agility Bonus when rolling Initiative.", category: "talent" },
  { id: "concealed-cavity", name: "Concealed Cavity", prerequisites: "", benefit: "Hide a fist-sized item in a secret body or augmetic compartment that is hard to find.", description: "The character's flesh or augmetics conceals a small compartment. The Explorer may conceal one small item, no larger than a closed fist, within this cavity. Discovering this compartment requires success on a Difficult (-10) Search Test. If using a medicae scanner or auspex, the Difficulty is reduced to Ordinary (+10).", category: "talent" },
  { id: "counter-attack", name: "Counter Attack", prerequisites: "Weapon Skill 40", benefit: "After a successful Parry, make an immediate Free Action attack with the parrying weapon at -20.", description: "The Explorer's lightning ripostes are things of beauty, if they were slow enough to be seen. After successfully Parrying an opponent's attack, he may immediately make an attack against that opponent using the Parry weapon as a Free Action. This attack suffers a -20 penalty.", category: "talent" },
  { id: "crack-shot", name: "Crack Shot", prerequisites: "Ballistic Skill 40", benefit: "Add +2 Damage when your ranged attack inflicts Critical Damage.", description: "The Explorer can place his shots where they will inflict more harm: at creases, gaps, or joints in armour. When his ranged attack causes Critical Damage, add +2 to the Damage.", category: "talent" },
  { id: "crippling-strike", name: "Crippling Strike", prerequisites: "Weapon Skill 50", benefit: "Add +4 Damage when your melee attack inflicts Critical Damage.", description: "The Explorer can land blows precisely where they will inflict the most harm, cutting into seams or hammering at weak points. When the character's melee attack causes Critical Damage, add +4 Damage.", category: "talent" },
  { id: "crushing-blow", name: "Crushing Blow", prerequisites: "Strength 40", benefit: "Add +2 Damage to melee attacks.", description: "The Explorer has the ability to focus his entire body into close combat attacks, adding +2 to Damage inflicted in melee.", category: "talent" },
  { id: "dark-soul", name: "Dark Soul", prerequisites: "", benefit: "Take only half the normal penalty on Malignancy tests.", description: "Prolonged exposure to darkness has acted as an inoculation against all that is foul, granting the Explorer resilience against corruption. Whenever he makes a Malignancy Test, he takes half the normal penalty.", category: "talent" },
  { id: "deadeye-shot", name: "Deadeye Shot", prerequisites: "Ballistic Skill 30", benefit: "Called shots only suffer a -10 penalty instead of -20.", description: "The Explorer's rock-steady hand and hawk-like eyesight make him a dreaded marksman. When making a called shot, the character takes a -10 penalty instead of -20.", category: "talent" },
  { id: "decadence", name: "Decadence", prerequisites: "Toughness 30", benefit: "Hold more drink before passing out and gain +10 to resist addiction.", description: "Through conditioning or long years of abuse, the Explorer has built up a tolerance to many inebriants, drugs, and chemicals. When drinking alcohol or similar beverages, he does not pass out until he has failed a number of Toughness Tests equal to twice his Toughness Bonus. The character also gains a +10 bonus to resist the effects of addiction.", category: "talent" },
  { id: "die-hard", name: "Die Hard", prerequisites: "Willpower 40", benefit: "When suffering blood loss, roll twice to avoid death.", description: "Through either willpower or sheer stubbornness, the Explorer refuses to cross into shadow. When he suffers from blood loss, the character may roll twice to avoid death.", category: "talent" },
  { id: "disarm", name: "Disarm", prerequisites: "Agility 30", benefit: "Use a Full Action opposed Weapon Skill test to knock an enemy's weapon away, or take it on 3+ Degrees of Success.", description: "The Explorer can wrest weapons from an opponent's hands through practiced technique or brute force. If in close combat, he may use a Full Action to disarm his foe by making an Opposed Weapon Skill Test. If he wins the Test, the opponent drops his weapon at his feet. If the character scores three or more Degrees of Success, he takes his opponent's weapon.", category: "talent" },
  { id: "disturbing-voice", name: "Disturbing Voice", prerequisites: "", benefit: "Gain +10 to Intimidate and Interrogation, but suffer -10 to non-threatening Fellowship tests.", description: "The Explorer's voice has particularly baleful or menacing qualities, causing others to quail before it. He gains a +10 bonus to all Intimidate or Interrogation Tests when he employs this Talent, but suffers a -10 penalty to Fellowship Tests when dealing with others in a non-threatening manner, such as animals, children, or the easily startled.", category: "talent" },
  { id: "divine-ministration", name: "Divine Ministration", prerequisites: "Pure Faith", benefit: "Spend Fate to greatly improve healing and fatigue recovery, or burn Fate to keep a just-slain character alive as Critically Wounded.", description: "The Explorer is a vessel for the Emperor's mercy and beneficence, his faith in His divinity can heal where no mere skill can. When testing Medicae, the Explorer may spend a Fate Point to restore an amount of Damage equal to his Willpower Bonus instead of the normal amount. He may spend a Fate Point to remove all Fatigue from a number of people equal to twice his Willpower Bonus. He may burn a Fate Point to allow a character who has just died to have become Critically Wounded instead, subject to the GM's approval.", category: "talent" },
  { id: "double-team", name: "Double Team", prerequisites: "", benefit: "Gain an extra +10 to Weapon Skill when ganging up on an opponent.", description: "The Explorer has the experience from many mass combats and swirling melees under his belt. When ganging up on an opponent, he gains an additional +10 bonus to Weapon Skill Tests. If both characters have this Talent, both gain an additional +10 bonus, for a total of +20. This bonus is in addition to the normal bonus gained from outnumbering opponents.", category: "talent" },
  { id: "dual-shot", name: "Dual Shot", prerequisites: "Agility 40, Two-Weapon Wielder (Ballistic)", benefit: "Fire two pistols at one target as a single Full Action attack without the normal two-weapon penalty.", description: "The Explorer's skill with guns is such that he can target two shots on exactly the same point. When armed with two pistols, he can fire both simultaneously as a Full Action. Make a single Ballistic Skill Test, and if successful he hits his target with both shots. He does not suffer the normal -20 Ballistic Skill penalty for wielding two weapons. If he hits, the target's Armour gets applied as normal to both hits individually, but Toughness only counts once against the combined Damage rolls of both hits. A single successful Dodge Test from the target will avoid both shots.", category: "talent" },
  { id: "dual-strike", name: "Dual Strike", prerequisites: "Agility 40, Two-Weapon Wielder (Melee)", benefit: "Attack with two melee weapons as a single Full Action strike without the normal two-weapon penalty.", description: "The Explorer's skill with melee weapons can place two blows together to maximise damage. When armed with two melee weapons, he can attack with both simultaneously as a Full Action. Make a single Weapon Skill Test, and if successful, he hits the target with both weapons. He does not suffer the normal -20 Weapon Skill penalty for wielding two weapons. If he hits, the target's Armour gets applied as normal to both hits individually, but Toughness only counts once against the combined Damage rolls of both hits. A single successful Dodge or Parry Test from the target will avoid both blows.", category: "talent" },
  { id: "duty-unto-death", name: "Duty Unto Death", prerequisites: "Willpower 45", benefit: "Ignore the effects of injury, Fatigue, and Stunning during combat.", description: "The Explorer's will or faith can sustain him when his flesh is weak. He ignores the effects of injury, Fatigue, and Stunning during combat. This Talent does not prevent the Damage, but allows the character to temporarily ignore its effects for the duration of the combat. Death still affects him normally.", category: "talent" },
  { id: "electrical-succour", name: "Electrical Succour", prerequisites: "Mechanicus Implants", benefit: "While touching a power source, remove Fatigue with a successful Toughness test.", description: "The Explorer can channel the sacred flow of energy from his Potentia Coil or other energy source to replenish his flesh. Whilst in contact with a functioning, powered machine, or fully charged battery or power cell, the character may make an Ordinary (+10) Toughness Test. Success removes one level of Fatigue plus one additional level of Fatigue for each additional Degree of Success. This takes one minute of meditation and ritual incantation.", category: "talent" },
  { id: "electro-graft-use", name: "Electro Graft Use", prerequisites: "Mechanicus Implants", benefit: "Gain +10 to Common Lore, Inquiry, or Tech-Use while connected to a data port.", description: "The Explorer may use his Electro Graft to access data ports and commune with machine spirits. This grants a +10 bonus to Common Lore, Inquiry, or Tech-Use Tests whilst connected to a data port.", category: "talent" },
  { id: "enemy", name: "Enemy", prerequisites: "", benefit: "Suffer an additional -10 to Fellowship tests with the chosen group.", description: "The opposite of Good Reputation, the Explorer is particularly despised by a specific social group or organisation. He suffers an additional -10 penalty to Fellowship Tests when dealing with this group. This Talent is cumulative with the Rival Talent, for a total -20 penalty.", category: "talent", groupKey: "enemy" },
  { id: "energy-cache", name: "Energy Cache", prerequisites: "Mechanicus Implants", benefit: "No longer gain Fatigue from Luminen Charge, Shock, or Blast.", description: "The Explorer has learned to focus the power stored within his Potentia Coil with greater efficiency. He no longer gains Fatigue from using Luminen Charge, Luminen Shock, and Luminen Blast.", category: "talent" },
  { id: "enhanced-bionic-frame", name: "Enhanced Bionic Frame", prerequisites: "Machinator Array", benefit: "Gain the Auto-Stabilised trait.", description: "The Explorer's already impressive bionic body structure is steadied by a gyro-array guided by a targeting system linked to the machine-spirit. The Explorer gains the Auto-stabilised Trait.", category: "talent" },
  { id: "exotic-weapon-training", name: "Exotic Weapon Training", prerequisites: "", benefit: "Use a specific exotic weapon without penalty.", description: "The Explorer has received Exotic Weapon Training in a single Exotic Weapon, and can use it without penalty.", category: "talent" },
  { id: "favoured-by-the-warp", name: "Favoured by the Warp", prerequisites: "Willpower 35", benefit: "When Psychic Phenomena occurs, roll twice and take the more favourable result.", description: "Whenever a Focus Power Test results in Psychic Phenomena, the Explorer may roll twice on that table and take the more favourable result.", category: "talent" },
  { id: "fearless", name: "Fearless", prerequisites: "", benefit: "Immune to Fear and Pinning, though backing down still requires a Willpower test.", description: "Through hard experience with horrifying situations, fear no longer commands the Explorer's actions. He is immune to the effects of Fear and Pinning, but disengaging from combat or backing down from a fight requires a successful Willpower Test.", category: "talent" },
  { id: "feedback-screech", name: "Feedback Screech", prerequisites: "Mechanicus Implants", benefit: "Unleash a shriek that forces nearby listeners to lose a Half Action unless they pass Willpower.", description: "The Explorer can haywire his vox synthesisers, causing a hideous blast of noise that shocks and distracts others. All unprotected creatures within a 30-metre radius who have the ability to hear must make a Willpower Test or lose a Half Action on their next Turn as they involuntarily react to the cacophonous shriek.", category: "talent" },
  { id: "ferric-lure", name: "Ferric Lure", prerequisites: "Mechanicus Implants", benefit: "Call unsecured metal objects to your hand with a Willpower test.", description: "The Explorer can cause an unsecured metal object within his field of vision to fly into his hand. The object may mass up to 1 kilogram per point of the character's Willpower Bonus, and must lie within 20 metres. Using this Talent requires a Full Action and a successful Willpower Test.", category: "talent" },
  { id: "ferric-summons", name: "Ferric Summons", prerequisites: "Mechanicus Implants, Ferric Lure", benefit: "Call larger metal objects from farther away than Ferric Lure.", description: "The Explorer can call an unsecured metal object to his hand as with Ferric Lure. But he may summon objects of up to 2 kilograms per point of his Willpower Bonus. The object may be up to 40 metres distant. The character must spend a Full Action and succeed on a Willpower Test to enact this rite.", category: "talent" },
  { id: "flame-weapon-training", name: "Flame Weapon Training", prerequisites: "", benefit: "Use non-Exotic flame weapons without penalty.", description: "The sight of flaming streams of promethium brings joy to the Explorer's heart and dread to his foes. He has mastered the art of a wide variety of flamer weapons. The Universal Talent group encompasses all non-Exotic weapons with the Flame special quality.", category: "talent", groupKey: "flameWeaponTraining" },
  { id: "foresight", name: "Foresight", prerequisites: "Intelligence 30", benefit: "Spend 10 minutes studying a problem to gain +10 to your next Intelligence test.", description: "Logic and analysis do for the Explorer what Tarot and the bones claim to do for the superstitious masses. By careful consideration of all the possible consequences, and examination of all evidence and information, he can identify the best path for success. By spending ten minutes studying or analysing a problem, he gains a +10 bonus to his next Intelligence Test.", category: "talent" },
  { id: "frenzy", name: "Frenzy", prerequisites: "", benefit: "Enter a furious rage for major melee bonuses at the cost of control and defense.", description: "The Explorer's temper and passion boil just below the surface of his psyche, mostly held in check by his rational mind, but easily released when needed. If the character spends one full Round fuelling his anger, on the next Round he goes into an uncontrolled rage, gaining a +10 bonus to Weapon Skill, Strength, Toughness, and Willpower, but suffering a -20 penalty to Ballistic Skill and Intelligence. He must attack the nearest enemy in melee if possible. While Frenzied, he is immune to Fear, Pinning, stunning effects, the effects of Fatigue, and he may not Parry, retreat, or flee. He remains Frenzied for the duration of the combat.", category: "talent" },
  { id: "furious-assault", name: "Furious Assault", prerequisites: "Weapon Skill 35", benefit: "After a successful All Out Attack, spend your Reaction to make an additional melee attack.", description: "The Explorer's speed and martial prowess allow him to land several blows where lesser combatants land one. If he successfully hits his target using the All Out Attack Action, he may spend his Reaction to make an additional attack using the same bonuses or penalties as the original attack.", category: "talent" },
  { id: "good-reputation", name: "Good Reputation", prerequisites: "Fellowship 50, Peer", benefit: "Gain an extra +10 to Fellowship tests with the chosen group.", description: "The Explorer's reputation precedes him in interactions with a specific group or organisation, opening doors that might otherwise remain closed. The Explorer gains an additional +10 bonus to Fellowship Tests when dealing with this group. This Talent is cumulative with Peer, for a total bonus of +20.", category: "talent", groupKey: "goodReputation" },
  { id: "guardian", name: "Guardian", prerequisites: "Agility 40", benefit: "Sacrifice your next round to swap places with an ally and take attacks meant for them.", description: "Years of serving as a bodyguard allow the Explorer to put himself in the line of fire, or to take a murderous attack that was intended for another. He may sacrifice all of his Actions for the next Round to switch places with an ally within 2 metres. This may be done at any time, even interrupting another action. The character become the target of any attacks previously targeting the ally. This Talent may not be used more than once per combat.", category: "talent" },
  { id: "gun-blessing", name: "Gun Blessing", prerequisites: "Mechanicus Implants", benefit: "Un-jam multiple nearby weapons with a Full Action Intelligence test.", description: "Using the Explorer's sacred ability to subtly affect ferrous materials, he can un-jam a number of weapons equal to his Intelligence Bonus, so long as they are within a 10-metre radius. A successful Intelligence Test indicates the character has appeased the spirits of the weapons. This blessing requires a Full Action.", category: "talent" },
  { id: "gunslinger", name: "Gunslinger", prerequisites: "Ballistic Skill 40, Two-Weapon Wielder", benefit: "Reduce the penalty for fighting with two pistols by 10.", description: "The Explorer has trained with pistols for so long that they are like extensions of his own body, barely requiring conscious thought to aim and fire. When armed with two pistols, he reduces the penalty for Two-Weapon Fighting by -10. If he also possesses the Ambidextrous Talent, the penalty is reduced to 0.", category: "talent" },
  { id: "hard-bargain", name: "Hard Bargain", prerequisites: "", benefit: "When Profit Factor is awarded for an Endeavour, the group gains +1 more Profit Factor.", description: "The Explorer's shrewd negotiations and bartering skills are without peer, and he has a knack for seeing opportunities for profit where others see nothing. Whenever Profit Factor is awarded for completing an Endeavour, you gain a bonus of +1 Profit Factor to the group's total.", category: "talent" },
  { id: "hard-target", name: "Hard Target", prerequisites: "Agility 40", benefit: "Gain -20 to be hit by ranged attacks after Charging or Running until your next turn.", description: "Light on his feet, the Explorer dodges and weaves as he moves, skills learned from long years in the line of fire. When he selects the Charge or Run Actions, opponents suffer a -20 penalty to Ballistic Skill Tests made to hit the character with a ranged weapon. This penalty continues until the start of the Explorer's next Turn.", category: "talent" },
  { id: "hardy", name: "Hardy", prerequisites: "Toughness 40", benefit: "Heal as if Lightly Wounded even when more seriously injured.", description: "The Explorer's constitution rebounds quickly from shock or injury. When undergoing medical treatment or healing from injuries, he recovers Damage as if Lightly Wounded.", category: "talent" },
  { id: "hatred", name: "Hatred", prerequisites: "", benefit: "Gain +10 Weapon Skill against the chosen hated foes in close combat.", description: "A group, organisation or race has wronged the Explorer in the past, fuelling this animosity. When fighting opponents of that group in close combat, he gains a +10 bonus to all Weapon Skill Tests made against them.", category: "talent", groupKey: "hatred" },
  { id: "heavy-weapon-training", name: "Heavy Weapon Training", prerequisites: "", benefit: "Use the chosen group of heavy weapons without the untrained penalty.", description: "The Explorer can employ some of the most devastating weapons of the battlefield. He can use weapons of the groups for which this Talent has been selected, choosing one new group each time. When a character attempts to use a weapon and he does not have the correct Weapon Training Talent for, he suffers a -20 penalty to any relevant Weapon Skill or Ballistic Skill Test.", category: "talent", groupKey: "heavyWeaponTraining" },
  { id: "heightened-senses", name: "Heightened Senses", prerequisites: "", benefit: "Gain +10 on tests that specifically rely on the chosen sense.", description: "Either genetics or augmetics have made one of the Explorer's senses superior to others. When he gains this Talent, select one of the five senses. The character gains a +10 bonus to any Tests specifically involving this sense.", category: "talent", groupKey: "heightenedSenses" },
  { id: "hip-shooting", name: "Hip Shooting", prerequisites: "Ballistic Skill 40, Agility 40", benefit: "Move up to Full Move and make a single ranged attack as one Full Action.", description: "The Explorer's prowess with ranged weapons is such that he can still fire accurately without using the sights. As a Full Action, the character may both move up to his Full Move rate and make a single attack with a ranged weapon. This attack can only be a single shot.", category: "talent" },
  { id: "hotshot-pilot", name: "Hotshot Pilot", prerequisites: "Any Pilot Skill, Agility 40", benefit: "Treat other Pilot skills as Basic and gain +10 to the one you already know.", description: "The Explorer can pilot vehicles as if they were extensions of his own body. He may only select this Talent if he has obtained one Pilot Skill as an Advanced Skill. The character treats all other Pilot skills as Basic Skills, and receives a +10 bonus to the Pilot Skills he already possesses.", category: "talent" },
  { id: "infused-knowledge", name: "Infused Knowledge", prerequisites: "Intelligence 40", benefit: "Treat all Common and Scholastic Lore skills as untrained Basic and gain +10 with ones you already know.", description: "The Explorer has been infused with a great wealth of lore and knowledge, either through punishing noetic techniques or by arcane methods kept secret by the guardians of technology and knowledge. The Explorer treats all Common and Scholastic Lore Skills as untrained Basic Skills. This Talent also provides a +10 bonus to any Tests involving Common or Scholastic Lore for which he already possesses the Skill.", category: "talent" },
  { id: "improved-warp-sense", name: "Improved Warp Sense", prerequisites: "Warp Sense", benefit: "Use Psyniscience as a Free Action.", description: "The Explorer can now see the warp and physical universe side by side, no longer taking any concentration on his part. After gaining this Talent, the character may use the Psyniscience Skill as a Free Action.", category: "talent" },
  { id: "independent-targeting", name: "Independent Targeting", prerequisites: "Ballistic Skill 40", benefit: "When firing two weapons at once, the targets no longer need to be within 10 metres of each other.", description: "The Explorer has developed his peripheral vision and situational awareness to a point where he can fire in two directions within a split second. When firing two weapons as part of a single action, the targets need not be less than 10 metres apart.", category: "talent" },
  { id: "into-the-jaws-of-hell", name: "Into the Jaws of Hell", prerequisites: "Iron Discipline", benefit: "Followers near you become immune to Fear and Pinning, and your ship gains +5 Morale while you are aboard.", description: "The Explorer inspires loyalty and devotion in his followers such that they would follow him into the warp or on a boarding action against xeno corsairs. In personal combat, while visible to them, they are immune to Fear and Pinning. While the character is known to be on board a ship in which he serves, the ship has a +5 bonus to its Morale.", category: "talent" },
  { id: "inspire-wrath", name: "Inspire Wrath", prerequisites: "Fellowship 30", benefit: "Gain +20 to inspire hatred or anger and affect double the normal number of listeners.", description: "The Explorer knows just the turn of phrase that incites individuals or groups to rage against others. His rhetoric grants +20 to Interaction Tests when inspiring hatred or anger, and double the number of individuals affected. This Talent can be combined with Master Orator to further increase the number of listeners affected.", category: "talent" },
  { id: "iron-discipline", name: "Iron Discipline", prerequisites: "Willpower 30, Command", benefit: "Followers under your command may re-roll failed tests against Fear and Pinning.", description: "Iron sharpens iron. The Explorer does not coddle his crew, nor motivate them through kindness. His stalwart example and stern leadership exhorts them with steel instead of spoils. If the character is visible to his followers, either in person or via vox- or pict-caster, they may re-roll failed Willpower Tests made to resist Fear and Pinning. Iron Discipline can affect a number of targets equal to the character's Willpower Bonus, who must be under his command.", category: "talent" },
  { id: "iron-jaw", name: "Iron Jaw", prerequisites: "Toughness 40", benefit: "Ignore Stunning with a successful Toughness test.", description: "The Explorer has taken blows from Orks and given back as good as he got. He can bounce back from most strikes without ill effects. If ever Stunned, a successful Toughness Test allows him to ignore the effects.", category: "talent" },
  { id: "jaded", name: "Jaded", prerequisites: "Willpower 30", benefit: "Ignore Fear and Insanity from ordinary horrors and atrocities, though the Warp still affects you normally.", description: "The Explorer's wide travels have shown both wonders and horrors beyond the ken of most. Outrageous events, from death's horrific visage to xenos abominations, will not cause Insanity Points or Fear Tests. Terrors of the Warp still affect the character normally.", category: "talent" },
  { id: "leap-up", name: "Leap Up", prerequisites: "Agility 30", benefit: "Stand up as a Free Action.", description: "A combination of athletic ability and speed allow the Explorer to spring to his feet in virtually any circumstance. He may stand up as a Free Action.", category: "talent" },
  { id: "last-man-standing", name: "Last Man Standing", prerequisites: "Nerves of Steel", benefit: "Become immune to Pinning from Pistols and Basic Weapons and gain +1 AP from cover against ranged attacks.", description: "The Explorer has developed a sixth sense about hails of gunfire, allowing him to sense gaps and pauses in the lethal rain. He is immune to Pinning by Pistols and Basic Weapons, and adds +1 AP to the value of any cover protecting him from ranged attacks.", category: "talent" },
  { id: "light-sleeper", name: "Light Sleeper", prerequisites: "Perception 30", benefit: "Always counts as awake for Awareness and surprise.", description: "The slightest change in conditions or disturbance brings the Explorer from sleep to full awareness, remaining alert even in slumber. He is always assumed to be awake, even when asleep, for the purposes of Awareness Tests or surprise.", category: "talent" },
  { id: "lightning-attack", name: "Lightning Attack", prerequisites: "Swift Attack", benefit: "Make three melee attacks as a Full Action.", description: "The Explorer's speed with weapons is legendary, allowing him to launch flurries of attacks. As a Full Action, the character may make three melee attacks on his Turn. The effects of this Talent replace those of Swift Attack rather than adding to them.", category: "talent" },
  { id: "lightning-reflexes", name: "Lightning Reflexes", prerequisites: "", benefit: "Add double your Agility Bonus to Initiative.", description: "The Explorer always expects trouble, even in the most innocuous situations, allowing him to act quickly when needed. The character adds twice his Agility Bonus when rolling for Initiative. If he has Unnatural Agility, add +1 to the multiplier before factoring the bonus into the Initiative roll.", category: "talent" },
  { id: "litany-of-hate", name: "Litany of Hate", prerequisites: "Hatred (Any)", benefit: "Extend the benefits of your Hatred talent to nearby allies with a successful Charm test.", description: "The Explorer's belief in the righteousness of his hatred is so ingrained that he can rouse others to join his crusade. As a Full Action, the character may make a Charm Test to extend the effects of his Hatred Talent to any allies in the immediate vicinity. Success on the Test confers a +10 bonus to Weapon Skill when fighting hated foes to one target per point of the Explorer's Fellowship Bonus. The effects last for the duration of the encounter.", category: "talent" },
  { id: "logis-implant", name: "Logis Implant", prerequisites: "", benefit: "Spend your Reaction and pass a Tech-Use test to gain +10 to Weapon Skill and Ballistic Skill until the end of your next turn.", description: "The Explorer may use analytical circuits to calculate trajectory and reactions to a preternatural extent. His ability to read possible outcomes lets him anticipate the movement of his opponents. By using his Reaction for the Round, the character may make a Tech-Use Test to make use of this Talent. He gains a +10 bonus to all Weapon Skill and Ballistic Skill Tests until the end of his next Turn. The Explorer must pass a Toughness Test when he uses this ability or gain a level of Fatigue.", category: "talent" },
  { id: "luminen-blast", name: "Luminen Blast", prerequisites: "Mechanicus Implants", benefit: "Channel Potentia Coil energy into a ranged Energy attack.", description: "The Omnissiah has blessed the Explorer with augmetic conduits that parallel the bones of his arms. By reciting the proper litany, he can channel the energy stored in his Potentia Coil down these channels and direct it at his enemies. Success on a Ballistic Skill Test allows him direct this energy against a single target within 10 meters. The target takes 1d10 plus the Explorer's Willpower Bonus in Energy Damage. The character must pass a Toughness Test when using this ability or gain a level of Fatigue. Talent Use: Half Action Attack.", category: "talent" },
  { id: "luminen-charge", name: "Luminen Charge", prerequisites: "Mechanicus Implants", benefit: "Recharge or power machinery with your Potentia Coil.", description: "The Explorer has mastered the union between his holy mechanical elements and his mortal flesh, allowing the former to power the latter. With a successful Toughness Test the character may recharge or power machinery with his internal coils. This requires one minute of meditation and ritual incantation. The Explorer must pass a Toughness Test when he uses this ability or gain a level of Fatigue.", category: "talent" },
  { id: "luminen-shock", name: "Luminen Shock", prerequisites: "Mechanicus Implants", benefit: "Channel Potentia Coil energy into a melee strike with Shocking.", description: "The power of the Explorer's Potentia Coil flows through a network of inductors within his flesh, allowing him to channel this energy into his blows. In close combat, a successful Weapon Skill Test or Grapple delivers the shock. The Luminen Shock inflicts 1d10+3 points of Energy Damage with the Shocking Quality. The Explorer must pass a Toughness Test when using this ability or gain a level of Fatigue. Talent Use: Half Action Attack.", category: "talent" },
  { id: "machinator-array", name: "Machinator Array", prerequisites: "Mechanicus Implants", benefit: "Gain major augmetic Strength and Toughness boosts at the cost of Agility and Fellowship.", description: "The Explorer has returned to the creches of the Mechanicus so they can bring him closer to the most holy of forms, adding an extensive machinator array to his existing augmetics. The Explorer's Strength and Toughness Characteristics are increased by +10, and his Agility and Fellowship are reduced by -5. His mass increases to three times that of a normal person, and he may no longer stay afloat or swim in water or similar liquids. The character may mount a single pistol type or close combat weapon on any Ballistic Mechadendrites he possesses. He must still have the proper Talent to use the mounted weapon.", category: "talent" },
  { id: "maglev-grace", name: "Maglev Grace", prerequisites: "Mechanicus Implants", benefit: "Hover just above the ground for a limited time and reduce falling damage.", description: "The Explorer stitches augmetic coils throughout the systems or flesh of his legs, granting him the ability to float a short distance above the ground. Using a Half Action, the character may hover 20 to 30 centimetres off the ground for a number of minutes equal to 1d10 plus his Toughness Bonus. The Explorer must employ a Half Action each round to maintain the rite, and may use the other actions to move normally. He may activate this rite to slow his rate of descent when falling, reducing all falling Damage to 1d10+3 Impact. Each use of Maglev Grace exhausts the power stored in the Potentia Coil.", category: "talent" },
  { id: "maglev-transcendence", name: "Maglev Transcendence", prerequisites: "Mechanicus Implants, Maglev Grace", benefit: "Hover farther and longer than Maglev Grace, with full negation of falling damage while active.", description: "The Explorer has proven his devotion to the Machine God by lacing augmetic coils through every portion of his body. Using a Half Action, he may hover 20 to 30 centimetres off the ground for a number of minutes equal to 2d10 plus his Toughness Bonus. He may move up to his running speed while maintaining the rite. He can slow his rate of descent when falling so long as this rite is active when he reaches the ground, taking no falling damage. Each time he enacts this rite, it drains 50% of his Potentia Coil.", category: "talent" },
  { id: "marksman", name: "Marksman", prerequisites: "Ballistic Skill 35", benefit: "Ignore range penalties at long and extreme range.", description: "The Explorer's steady hand and eagle eye allows him to keep crosshairs steady on any target, regardless of range. Distance is no protection against his fire. The Explorer suffers no penalties for Ballistic Skill Tests at long or extended range.", category: "talent" },
  { id: "master-and-commander", name: "Master & Commander", prerequisites: "Intelligence 35, Fellowship 35", benefit: "Direct allies or armsmen to ignore ganging up penalties and fight more effectively.", description: "There can be only one commander of a vessel, and the Explorer's guiding hand, stern judgment, and sage leadership have captained his crew through countless conflicts. By spending a Half Action in combat to direct the efforts of his allies, none of them suffer the penalties for ganging up until his next Turn. If defending against a boarding action, a Half Action directs the efforts of his armsmen, granting them a +10 bonus in combat.", category: "talent" },
  { id: "master-chirurgeon", name: "Master Chirurgeon", prerequisites: "Medicae +10", benefit: "Gain +10 to Medicae, heal heavily wounded patients better, and improve protection against limb loss.", description: "The Explorer's advanced medical skills enable him knit flesh with deft mastery. His exceptional education in use of the Narthecium, Med-Slate, and supplemental drugs gives his patients an enormous advantage. The Explorer gains a +10 bonus on all Medicae Tests. If treating a Heavily or Critically Wounded patient, a successful Test heals 2 points of Damage instead of 1. If the patient is in danger of losing a limb from a Critical Hit, the Explorer provides him with a +20 bonus to the Toughness Test to prevent limb loss.", category: "talent" },
  { id: "master-enginseer", name: "Master Enginseer", prerequisites: "Tech-Use +20, Mechanicus or Explorator Implants", benefit: "Spend Fate for automatic success on starship Tech-Use for enhancement, repair, or upgrade.", description: "The Explorer's knowledge of starships and their machine spirits surpasses all his planet-bound brethren. The character can almost feel the plasma pulsing through the ship's conduits as if it were his own veins. He may spend a Fate Point for automatic success on a Tech-Use Test for enhancement, repair, or upgrade of starship systems, taking the minimum amount of time possible on the task.", category: "talent" },
  { id: "master-orator", name: "Master Orator", prerequisites: "Fellowship 30", benefit: "Your Fellowship tests affect 10 times the normal number of targets.", description: "The Explorer has learned the techniques required to influence large audiences. His Fellowship Tests and Fellowship-based Skill Tests affect 10 times the normal number of targets.", category: "talent" },
  { id: "mechadendrite-use", name: "Mechadendrite Use", prerequisites: "Explorator", benefit: "Use the chosen category of mechadendrites.", description: "Though there are many different types of Mechadendrite, this Talent divides them into two broad categories: Weapon, for mechadendrites ending in ranged or close combat weapons with the support and strength necessary for combat; and Utility, for machine spirit interface, manipulator, medicae, optical, and similar varieties that interface with the cyber mantle in a similar manner.", category: "talent" },
  { id: "meditation", name: "Meditation", prerequisites: "", benefit: "After 10 uninterrupted minutes and a successful Willpower test, remove 1 Fatigue.", description: "The Explorer has mastered his body and its reactions by prayer to the Emperor, shutting down unnecessary functions to refresh his body and mind. Success on a Willpower Test and 10 minutes without interruptions removes one level of Fatigue.", category: "talent" },
  { id: "melee-weapon-training", name: "Melee Weapon Training", prerequisites: "", benefit: "Use the chosen group of melee weapons without the untrained penalty.", description: "The Explorer has trained extensively with hand-to-hand weaponry, becoming proficient in the use of virtually all hand-held close combat arms. The Universal group includes the Chain, Shock, and Power groups, and allows proficient use of all those weapon types. When a character attempts to use a weapon he does not have the correct Weapon Training Talent for, he suffers a -20 penalty to any relevant Weapon Skill or Ballistic Skill Test.", category: "talent", groupKey: "meleeWeaponTraining" },
  { id: "mighty-shot", name: "Mighty Shot", prerequisites: "Ballistic Skill 40", benefit: "Add +2 Damage with ranged weapons.", description: "The Explorer knows the weak points in every armour and material, and has the skill to place shots exactly where they will do the most damage. He adds +2 to Damage with a ranged weapon.", category: "talent" },
  { id: "mimic", name: "Mimic", prerequisites: "", benefit: "After study, accurately imitate another's voice well enough to deceive listeners.", description: "Vox synthesisers, training or innate abilities allow the Explorer to accurately mimic the voice of another. He must study the voice patterns of his target for at least one hour for proper imitation, and speak the same language. Listeners must succeed on a Difficult (-10) Scrutiny Test to penetrate the deception. If the character studies used vox recordings or comm-link conversations rather than in-person observation, the Difficulty of the Scrutiny Test is reduced to Challenging (+0). His deception automatically fails if the listener can clearly see he is not the imitated individual.", category: "talent" },
  { id: "navigator", name: "Navigator", prerequisites: "", benefit: "You possess the Navigator gene and the Warp Eye.", description: "The Explorer was born with the Navigator gene, either of the Navis Nobilite or in the shadowed ranks of the unlicensed. The Warp Eye stares balefully from his forehead, allowing him to perceive the ebbs and flows of the empyrean. For more details, see Navigator Powers.", category: "talent" },
  { id: "navigator-power", name: "Navigator Power", prerequisites: "Navigator", benefit: "Gain an additional Navigator Power.", description: "The Explorer's trainers or natural ability allows use of an additional Navigator Power. This Talent may be chosen multiple times, each selection granting a new Power.", category: "talent" },
  { id: "nerves-of-steel", name: "Nerves of Steel", prerequisites: "", benefit: "Re-roll failed Willpower tests to avoid or recover from Pinning.", description: "Long years on the battlefield enable the Explorer to remain calm as fire impacts all around. He may re-roll failed Willpower Tests to avoid or recover from Pinning.", category: "talent" },
  { id: "orthoproxy", name: "Orthoproxy", prerequisites: "", benefit: "Gain +20 to Willpower tests against mind control or interrogation.", description: "A liturgical circuit has been implanted within the Explorer's skull, allowing him to focus on the prayers recited by the proxy unit when his mental fortitude is in peril. He receives a +20 bonus to Willpower Tests made to resist mind control or interrogation.", category: "talent" },
  { id: "paranoia", name: "Paranoia", prerequisites: "", benefit: "Gain +2 Initiative and the GM may test Perception secretly for hidden threats.", description: "The Explorer knows that danger lurks behind every corner and knows the galaxy will hit him as soon as he lets his guard down. The character gains a +2 bonus on Initiative rolls, and the GM may secretly Test his Perception to notice hidden threats. The price of his eternal vigilance is a twitchy disposition and the inability to relax.", category: "talent" },
  { id: "peer", name: "Peer", prerequisites: "Fellowship 30", benefit: "Gain +10 to Fellowship tests with the chosen social group.", description: "The Explorer is adept at dealing with a particular social group or organisation. He gains a +10 bonus to all Fellowship Tests when interacting with the chosen group.", category: "talent", groupKey: "peer" },
  { id: "pistol-weapon-training", name: "Pistol Weapon Training", prerequisites: "", benefit: "Use the chosen group of pistol weapons without the untrained penalty.", description: "The Explorer has practiced with nearly every single-handed ranged weapon within the confines of the Imperium, and no small number without. The Universal group confers proficiency with most pistol weapons, including the Bolt, Las, Launcher, Melta, Plasma, and SP groups. When a character attempts to use a weapon he does not have the correct Weapon Training Talent for, he suffers a -20 penalty to any relevant Weapon Skill or Ballistic Skill Test.", category: "talent", groupKey: "pistolWeaponTraining" },
  { id: "polyglot", name: "Polyglot", prerequisites: "Intelligence 40, Fellowship 30", benefit: "Treat all languages as Basic Skills, though with a -10 penalty.", description: "The Explorer has an innate ability to derive meaning from unknown languages and make himself understood using this intuitive grasp. He treats all languages as Basic Skills. This is not the same as true knowledge of the language, and tests using this Talent suffer a -10 penalty due to the simplistic nature of translation.", category: "talent" },
  { id: "precise-blow", name: "Precise Blow", prerequisites: "Weapon Skill 40, Sure Strike", benefit: "Ignore the called shot penalty when making called shots in melee.", description: "The Explorer's eye, hand, and weapon act seamlessly together, placing blows exactly where the attacker intends. When making a called shot with a melee weapon, the Explorer does not incur the -20 penalty.", category: "talent" },
  { id: "prosanguine", name: "Prosanguine", prerequisites: "Autosanguine", benefit: "Meditate and test Tech-Use to heal 1d5 Damage using your autosanguinators.", description: "Through the Explorer's iron will or via appeals to the Omnissiah, he is able to speed the function of his Autosanguinators. By spending 10 minutes in meditation and ritual incantation, the character may make a Tech-Use Test, and if successful, remove 1d5 points of Damage. If he rolls a 96-100, he overstrains his implants, losing the ability to use them for one week. During that week, the Explorer may use neither the Autosanguine nor Prosanguine Talents.", category: "talent" },
  { id: "psy-rating", name: "Psy Rating", prerequisites: "", benefit: "Increase your Psy Rating by 1 each time you take this talent.", description: "The Explorer is a psyker, and his power in game terms is rated on a scale of 1 to 10. Increasing a character's Psy Rating represents that character unlocking more of his psychic potential and becoming more powerful. An Explorer can take this Talent multiple times; each time it is taken, his current Psy Rating increases by 1.", category: "talent" },
  { id: "psychic-discipline", name: "Psychic Discipline", prerequisites: "", benefit: "Gain access to a new Psychic Discipline.", description: "The Explorer gains access to a new Psychic Discipline, and may select techniques from this new field of study as his abilities increase. Psykers may access a maximum of three separate Disciplines.", category: "talent" },
  { id: "psychic-technique", name: "Psychic Technique", prerequisites: "", benefit: "Learn an additional Psychic Technique you are qualified to purchase.", description: "Either through training or natural development, the Explorer has learned an additional Psychic Technique. Once this Talent has been selected, the Explorer may select one new Psychic Technique in any Discipline he possesses with an xp cost equal to or lower than the Talent's xp cost. This Talent may be chosen multiple times, each selection granting an additional Technique.", category: "talent" },
  { id: "pure-faith", name: "Pure Faith", prerequisites: "", benefit: "Gain broad protection against daemonic influence and psychic harm by spending or burning Fate.", description: "The Explorer's faith in the God Emperor of Mankind, his divine power and grace, is total and complete. Pure Faith provides all of the following benefits: the Explorer is always immune to the effects of Daemonic Presence, including negative modifiers to Willpower; by spending a Fate Point he may avoid Fear Tests, Insanity Points, and Corruption Points for the duration of the encounter; and by burning a Fate Point he may resist the effects of any single daemonic or psychic attack, emerging unscathed as if by a miracle.", category: "talent" },
  { id: "purge-the-unclean", name: "Purge the Unclean", prerequisites: "Pure Faith", benefit: "Spend or burn Fate to repel, exorcise, or harm warp entities with faith.", description: "The Explorer can focus his faith through words, gestures, and force of will such that a daemon may be cowed or cast out by the power of the Emperor. As a half action he may spend a Fate Point to repel a warp entity. As a full action he may spend a Fate Point to force out a possessing warp entity from its host. As a full action he may burn a Fate Point to chant the litanies of detestation to purge a warp entity from reality, dealing direct harm not reduced by Toughness or Armour.", category: "talent" },
  { id: "quick-draw", name: "Quick Draw", prerequisites: "", benefit: "Ready one-handed melee weapons, pistols, or basic weapons as a Free Action.", description: "The Explorer has practised so frequently with his weapons that they practically leap into his hands, ready for action. He can Ready as a Free Action when armed with a Pistol or Basic class ranged weapon, or a melee weapon that can be wielded in one hand.", category: "talent" },
  { id: "rapid-reaction", name: "Rapid Reaction", prerequisites: "Agility 40", benefit: "Act normally when surprised with a successful Agility test.", description: "The Explorer has honed his reactions to a razor's edge, allowing him to act while most stand dumbfounded. When surprised or ambushed, a successful Agility Test allows him to act normally.", category: "talent" },
  { id: "rapid-reload", name: "Rapid Reload", prerequisites: "", benefit: "Halve all reload times, rounding down.", description: "The practice bays aboard the Explorer's vessel are like a second home, and he has reloaded countless magazines or power cells for his weapons until he can replace them with his eyes closed. The Explorer halves all reload times, rounding down. Thus, Half Action reload becomes a Free Action, a Full Action reload becomes a Half Action, and so on.", category: "talent" },
  { id: "renowned-warrant", name: "Renowned Warrant", prerequisites: "", benefit: "Gain +10 to Interaction tests with those who respect a famous Warrant of Trade.", description: "The Explorer's Warrant of Trade is ancient and hallowed, signed before the Imperium knew of the Expanse, and garners the respect of merchants and officials alike. The character gains a +10 bonus to Interaction Skill Tests with those who understand the importance of the warrant, such as other traders and Imperial officials.", category: "talent" },
  { id: "resistance", name: "Resistance", prerequisites: "", benefit: "Gain +10 to tests to resist the chosen hardship.", description: "The Explorer's background, experience, training, exposure, or plain stubbornness has inured him to a particular type of hardship. Each time the Explorer selects this Talent, choose one group. He gains a +10 bonus when making Tests to resist the effects of this group.", category: "talent", groupKey: "resistance" },
  { id: "rite-of-awe", name: "Rite of Awe", prerequisites: "Explorator", benefit: "Impose a -10 penalty to the next Skill Test of nearby humans with an infrasonic litany.", description: "The Omnissiah has augmetically blessed the Explorer's voice box, allowing him to recite infrasonic litanies that trigger awe and fear. All humans within a 50-metre radius feel a sense of dread and take a -10 penalty to their next Skill Test. Characters may ignore these effects with a successful Willpower Test. The rite requires two minutes of litanies, and whilst incanting it the character may not talk or communicate with others.", category: "talent" },
  { id: "rite-of-fear", name: "Rite of Fear", prerequisites: "Explorator", benefit: "Project Fear (1) to nearby humans with an infrasonic dirge.", description: "The Explorer's infrasonic dirges cause terror in the weak. All humans within a 50-metre radius treat the character as if he has a Fear Rating of 1. While incanting the dirge, he may not communicate in any other way. The rite requires two minutes of chanting, and humans without auditory augmentation cannot hear the sound even though they are still affected.", category: "talent" },
  { id: "rite-of-pure-thought", name: "Rite of Pure Thought", prerequisites: "Explorator", benefit: "Become immune to Fear, Pinning, and emotion-based effects through cranial circuitry.", description: "The Explorer has replaced the creative half of his brain with sacred cranial circuitry. He can no longer feel emotion, and instead embraces the crystal purity of logic, making him immune to Fear, Pinning, and any effects that stem from emotional disturbance. The GM will remove any Mental Disorders that no longer apply, and grant appropriate new ones of equal severity.", category: "talent" },
  { id: "rite-of-sanctioning", name: "Rite of Sanctioning", prerequisites: "Psy Rating, Special", benefit: "Choose a trademark Psychic Phenomena result you can substitute for non-Perils rolls.", description: "The Explorer has been brought before the Emperor and has received a miniscule fraction of His strength, making him more resistant to the predations of the Warp. Choose one result on the Psychic Phenomena table other than Perils of the Warp. When rolling for Psychic Phenomena, the Explorer may substitute his trademark result for the effect rolled on the table, so long as he does not roll Perils of the Warp.", category: "talent" },
  { id: "rival", name: "Rival", prerequisites: "", benefit: "Suffer -10 to Fellowship tests with the chosen group.", description: "This Talent represents aggressive competition and animosity with a particular social group or organisation. The Explorer suffers a -10 penalty to all Fellowship Tests when interacting with the chosen group.", category: "talent", groupKey: "rival" },
  { id: "sharpshooter", name: "Sharpshooter", prerequisites: "Ballistic Skill 40, Deadeye Shot", benefit: "Ignore the called shot penalty with ranged attacks.", description: "The Explorer's steady hand and eagle eye allow him to place shots exactly where he wants. When making a called shot, he does not incur the normal -20 penalty. This Talent replaces the effects of Deadeye Shot.", category: "talent" },
  { id: "sound-constitution", name: "Sound Constitution", prerequisites: "", benefit: "Gain 1 additional Wound each time this talent is taken.", description: "The Explorer gains an additional Wound. He may purchase this Talent multiple times in accordance with his Career Advances, noting the number of times it has been taken.", category: "talent" },
  { id: "sprint", name: "Sprint", prerequisites: "", benefit: "Move farther on Full Move and double movement for one round when Running.", description: "The Explorer's fleet feet can propel him faster than his comrades. When taking the Full Move Action, the character can move an extra number of metres equal to his Agility Bonus. When taking the Run Action, he may double his movement for one Round. The Explorer gains one level of Fatigue if he uses this Talent two Turns in a row.", category: "talent" },
  { id: "step-aside", name: "Step Aside", prerequisites: "Agility 40, Dodge", benefit: "Gain one extra Dodge Reaction each round.", description: "The Explorer can sway his body out of the path of an attack, causing it to pass through thin air. He may make an additional Dodge once per Round. In effect this gives him a second Reaction that may only be used to Dodge, though he may still only attempt a single Dodge against one attack.", category: "talent" },
  { id: "strong-minded", name: "Strong Minded", prerequisites: "Willpower 30, Resistance (Psychic Techniques)", benefit: "Re-roll failed Willpower tests against psychic powers that target your mind.", description: "The Explorer's mind acts as a fortress against psychic attacks. He may re-roll failed Willpower Tests to resist any Psychic Techniques that affect his mind. Psychic Techniques that have a physical effect, such as Telekinesis, are unaffected by this Talent.", category: "talent" },
  { id: "sure-strike", name: "Sure Strike", prerequisites: "Weapon Skill 30", benefit: "Choose between the rolled melee hit location and its reversed digits.", description: "The Explorer can direct his blows far better than most, giving him some control over where they land. When determining hit location for a melee attack, he may use the dice as rolled or reverse them, choosing the location he prefers.", category: "talent" },
  { id: "swift-attack", name: "Swift Attack", prerequisites: "Weapon Skill 35", benefit: "Make two melee attacks as a Full Action.", description: "The Explorer's speed and martial ability allow him to land flurries of blows. As a Full Action, he may make two melee attacks on his Turn. If he has Two-Weapon Wielder, he gains the advantage of Swift Attack with only one melee weapon and a single attack with the other.", category: "talent" },
  { id: "takedown", name: "Takedown", prerequisites: "", benefit: "Use a Half Action attack to stun instead of dealing damage, without the usual Stun penalty.", description: "As a Half Action the Explorer may declare that he is attempting a takedown before testing Weapon Skill. If he hits and would have done at least 1 point of Damage, ignore the Damage and the opponent must make a Toughness Test or be Stunned for 1 Round. When performing a Stun Action, the character does not suffer the normal -20 penalty to Weapon Skill.", category: "talent" },
  { id: "talented", name: "Talented", prerequisites: "", benefit: "Gain +10 to tests with the chosen skill.", description: "The Explorer has a natural affinity for a particular Skill. He chooses one Skill and gains a +10 bonus to Tests made using that Skill.", category: "talent", groupKey: "talented" },
  { id: "technical-knock", name: "Technical Knock", prerequisites: "Intelligence 30", benefit: "Clear a jammed gun as a Half Action once per round.", description: "Either through ease of long practice, or the proper ritual to appease a weapon's machine spirit, the Explorer can clear stoppages in weapons. He may un-jam any gun as a Half Action, but may only perform this rite on one weapon per Round. He must touch the weapon to enact this rite.", category: "talent" },
  { id: "the-emperor-protects", name: "The Emperor Protects", prerequisites: "Pure Faith", benefit: "Spend or burn Fate to protect yourself and allies from fear, pinning, and attacks.", description: "The power of the Emperor flows through the Explorer, protecting the faithful and emboldening them to heroism in the face of terrible things. By spending a Fate Point, the character grants himself and a number of allies equal to his Willpower Bonus immunity to the effects of Fear and Pinning, and attacks made against them suffer a -10 modifier for the duration of the encounter. By burning a Fate Point, the character may allow an ally to resist the effects of a single attack and emerge unscathed as if by a miracle.", category: "talent" },
  { id: "the-flesh-is-weak", name: "The Flesh is Weak", prerequisites: "Mechanicus Implants", benefit: "Gain the Machine trait with Armour Points equal to the number of times taken.", description: "The Explorer's body has undergone significant bionic replacement to the point where he is far more machine than man. This Talent grants the Explorer the Machine Trait with Armour Points equal to the number of times this Talent has been taken. The Explorer may purchase this Talent multiple times in accordance with his Career Advances.", category: "talent" },
  { id: "thrown-weapon-training", name: "Thrown Weapon Training", prerequisites: "", benefit: "Use thrown weapons without the untrained penalty.", description: "The Explorer's mastery of the balance, spin, and weight of thrown weapons makes him a formidable foe at any distance, even if only armed with a knife. The Universal group includes all thrown weapons from the Primitive, Chain, Shock, and Power groups. When a character attempts to use a weapon he does not have the correct Weapon Training Talent for, he suffers a -20 penalty to any relevant Weapon Skill or Ballistic Skill Test.", category: "talent", groupKey: "thrownWeaponTraining" },
  { id: "total-recall", name: "Total Recall", prerequisites: "Intelligence 30", benefit: "Possess near-perfect memory for facts and previously encountered details.", description: "Mental conditioning or augmetics enable the Explorer to record and recall great amounts of information, effectively granting him a perfect memory. He can automatically remember trivial facts or pieces of information that he might feasibly have picked up in the past. For more detailed, complex, or obscure facts, the GM may still require an Intelligence Test.", category: "talent" },
  { id: "true-grit", name: "True Grit", prerequisites: "Toughness 40", benefit: "Halve Critical Damage suffered, rounding up.", description: "The Explorer is able to shrug off wounds that would fell lesser men. Whenever he suffers Critical Damage, halve the result, rounding up.", category: "talent" },
  { id: "two-weapon-wielder", name: "Two-Weapon Wielder", prerequisites: "Ballistic Skill 35 or Weapon Skill 35, Agility 35", benefit: "Attack with two weapons of the chosen type as a Full Action.", description: "Years of training allow the Explorer to use a weapon in each hand when needed. When armed with two weapons of the same type, he may spend a Full Action to attack with both. Both tests made to attack with the weapons suffer a -20 penalty. He must possess both the Melee and Ballistic versions if he wishes to use a gun and a hand weapon with this Talent.", category: "talent", groupKey: "twoWeaponWielder" },
  { id: "unarmed-master", name: "Unarmed Master", prerequisites: "Weapon Skill 45, Agility 40, Unarmed Warrior", benefit: "Improve unarmed attacks to 1d10+SB Impact and remove Primitive.", description: "The Explorer has developed unequalled mastery of unarmed combat techniques. His unarmed combat attacks do 1d10 plus his Strength Bonus in Impact Damage and his attacks no longer have the Primitive quality.", category: "talent" },
  { id: "unarmed-warrior", name: "Unarmed Warrior", prerequisites: "Weapon Skill 35, Agility 35", benefit: "Improve unarmed attacks to 1d10-3+SB and do not count as unarmed against armed foes.", description: "Due to extensive training in unarmed combat, the Explorer's unarmed combat attacks do 1d10-3 plus his Strength Bonus in Damage instead of 1d5-3. Because of his advanced training against both armed and unarmed foes, he does not count as Unarmed when making attacks against armed opponents. The character's attacks still count as having the Primitive quality.", category: "talent" },
  { id: "unremarkable", name: "Unremarkable", prerequisites: "", benefit: "Blend into crowds so attempts to notice, describe, or remember you suffer a -20 penalty.", description: "The Explorer has mastered the art of blending into any crowd by adopting its mannerisms. Attempts to notice the character when amongst other people, or attempts to describe him or recall details incur a -20 penalty.", category: "talent" },
  { id: "unshakeable-faith", name: "Unshakeable Faith", prerequisites: "", benefit: "Re-roll failed Willpower tests against Fear.", description: "The Explorer's confidence in the Emperor and his abilities is so strong that he can face any danger. He may re-roll any failed Willpower Tests to avoid the effects of Fear.", category: "talent" },
  { id: "void-tactician", name: "Void Tactician", prerequisites: "Intelligence 35", benefit: "Gain +10 to Ballistic Skill when firing a starship's guns in combat.", description: "The Explorer's ability to conceptualise three-dimensional space gives him an advantage in starship combat, granting a +10 bonus to Ballistic Skill Tests made to fire a starship's guns in combat.", category: "talent" },
  { id: "wall-of-steel", name: "Wall of Steel", prerequisites: "Agility 35", benefit: "Gain one extra Parry Reaction each round.", description: "The Explorer's skill with blades is so profound that the merest hint of attack allows him to assume a defensive position. He may make one additional Parry per Round, in effect granting a second Reaction that may only be used to Parry. He may only attempt a single Parry against any one attack.", category: "talent" },
  { id: "warp-affinity", name: "Warp Affinity", prerequisites: "Psy Rating", benefit: "Discard a Psychic Phenomena roll, take 1d5 Corruption, and re-roll the phenomena.", description: "The Explorer has a special connection to the warp, allowing him to occasionally sense and avoid its less desirable effects as he channels its power. When rolling for Psychic Phenomena, the Explorer may discard the die roll, suffer 1d5 Corruption Points, and then re-roll with no modifiers.", category: "talent" },
  { id: "warp-conduit", name: "Warp Conduit", prerequisites: "Psy Rating, Strong Minded, Willpower 50", benefit: "When pushing, gain +1 Psy Rating and -10 to the Psychic Phenomena roll.", description: "The sheer power of the Explorer's mind allows him to channel much more warp energy than his peers. When pushing, he may add a +1 bonus to his Psy Rating and subtract -10 on any resultant Psychic Phenomena rolls.", category: "talent" },
  { id: "warp-sense", name: "Warp Sense", prerequisites: "Navigator or Psy Rating, Psyniscience, Perception 30", benefit: "Use Psyniscience as a Half Action.", description: "The Explorer's senses have evolved to perceive the warp in parallel with the physical world, though it requires some concentration to do so. After gaining this Talent, using the Psyniscience Skill requires a Half Action instead of a Full Action.", category: "talent" },
  { id: "whispers", name: "Whispers", prerequisites: "Intelligence 45, Fellowship 35", benefit: "Gain +10 to Investigation tests and Interview-style Inquiry among the crew.", description: "Such is the Explorer's reputation for having ears everywhere aboard the ship and a finely tuned network of invisible informants that the crew no longer even bothers to keep secrets from him. The Explorer receives a +10 bonus to Skill Tests for Investigation or the Interview special use of the Inquiry Skill.", category: "talent" },
  { id: "wrath-of-the-righteous", name: "Wrath of the Righteous", prerequisites: "Pure Faith", benefit: "Spend Fate for extra damage or burn Fate for automatic Righteous Fury.", description: "The Explorer is a killing angel, and he visits the Emperor's righteous fury on those who deny His dominion over the stars or profane that which is sacred. When making an attack, the Explorer may spend a Fate Point to deal an additional 1d5 points of Damage. He may also burn a Fate Point to trigger Righteous Fury on a single successful attack, causing it to deal maximum weapon Damage plus 1d10 extra Damage, with further Damage possible if the additional die also results in 10.", category: "talent" }
];

const TRAIT_DEFINITIONS = [
  { id: "auto-stabilised", name: "Auto-Stabilised", prerequisites: "", benefit: "Always counts as braced with heavy weapons and can move and fire on semi- or full-auto without the usual penalties.", description: "A creature with this Trait is automatically treated as braced when firing heavy weapons. It may fire semi-automatic or full-automatic attacks as a Half Action, and ignores the normal penalties for moving and firing on those attack modes.", category: "trait" },
  { id: "bestial", name: "Bestial", prerequisites: "", benefit: "Acts on instinct, ignores Survival tests in its natural habitat, and may flee when frightened, startled, or hurt.", description: "This creature behaves as a beast regardless of its raw Intelligence. It never needs to make Survival Tests in its native environment. Unless starving or desperate, it must make a Willpower Test when frightened, startled, or injured; on a failure, it flees.", category: "trait" },
  { id: "blind", name: "Blind", prerequisites: "", benefit: "Automatically fails sight-based tests and Ballistic Skill tests, and suffers a major penalty in melee and other sight-reliant situations.", description: "A blind creature automatically fails all Tests based on vision and automatically fails all Ballistic Skill Tests. It takes a -30 penalty to Weapon Skill Tests and most other Tests that would normally rely on sight or benefit from vision.", category: "trait" },
  { id: "brutal-charge", name: "Brutal Charge", prerequisites: "", benefit: "Deals +3 damage on Charge attacks.", description: "When this creature makes attacks as part of a Charge, those attacks deal an additional 3 points of Damage.", category: "trait" },
  { id: "burrower", name: "Burrower", prerequisites: "", benefit: "Can tunnel through solid matter at the listed speed, usually leaving a passage behind.", description: "A creature with this Trait can move through earth, rock, sand, and similar material by tunnelling. Use the item's rating or notes to record the burrow speed and any special cases, such as tunnelling through metal. Burrowing normally leaves a tunnel behind that smaller creatures can traverse, though it may collapse after the burrower passes.", category: "trait" },
  { id: "crawler", name: "Crawler", prerequisites: "", benefit: "Moves at half Agility Bonus, rounded up, but ignores difficult terrain penalties from crawling or slithering.", description: "Worm-like, serpentine, or slithering creatures use half their Agility Bonus, rounded up, as base movement. They do not suffer penalties for moving across difficult terrain because their bodies are built for creeping or slithering movement.", category: "trait" },
  { id: "daemonic", name: "Daemonic", prerequisites: "", benefit: "Doubles Toughness Bonus against most damage and is immune to poison and disease.", description: "Daemonic creatures are anchored to reality by the Warp. They double their Toughness Bonus against all Damage except damage from force weapons, psychic powers, holy attacks, or attacks by other daemonic beings. They are also immune to poison and disease.", category: "trait" },
  { id: "dark-sight", name: "Dark Sight", prerequisites: "", benefit: "Sees normally in darkness and ignores penalties from dim or absent light.", description: "This creature can see without penalty in total darkness and never suffers combat penalties from low light, darkness, or the absence of lighting.", category: "trait" },
  { id: "fear", name: "Fear", prerequisites: "", benefit: "Forces observers to make a Willpower Test or suffer Shock; use the rating field for Fear 1-4.", description: "A creature with this Trait is unnerving or horrifying to behold. Record the Fear Rating in the item's rating field. Those who encounter it must make a Willpower Test modified by the severity of the Trait. On a failure, they roll on the Shock Table and add +10 for every 10 points by which the Test was failed.", category: "trait" },
  { id: "flyer", name: "Flyer", prerequisites: "", benefit: "Can fly at the listed speed instead of using normal movement.", description: "This creature is capable of true flight. Use the item's rating or notes to record the flying speed; that value replaces Agility Bonus for Movement Actions while airborne.", category: "trait" },
  { id: "from-beyond", name: "From Beyond", prerequisites: "", benefit: "Immune to Fear, Pinning, Insanity Points, and mind-clouding or mind-controlling psychic effects.", description: "The creature's mind lies outside normal mortal frailties. It is immune to Fear, Pinning, Insanity Points, and psychic powers that cloud, control, or delude the mind.", category: "trait" },
  { id: "hoverer", name: "Hoverer", prerequisites: "", benefit: "Can fly close to the ground at the listed speed.", description: "A creature with this Trait can fly, but only at low altitude, usually no more than two metres above the ground. Use the item's rating or notes to record the hover speed.", category: "trait" },
  { id: "incorporeal", name: "Incorporeal", prerequisites: "", benefit: "Can pass through solid matter, hides well inside objects, and ignores normal weapons unless special rules say otherwise.", description: "Incorporeal creatures are weightless and insubstantial. They gain a +30 bonus to Concealment when hiding inside objects and automatically pass Silent Move Tests when appropriate. Normal weapons pass through them harmlessly; only daemons, psychic powers, force weapons, Warp entities, holy effects, and similarly supernatural attacks can usually harm them. They also cannot normally affect the material world unless a special rule allows it.", category: "trait" },
  { id: "machine", name: "Machine", prerequisites: "", benefit: "Ignores many biological hazards and gains Armour Points from its machine body; use the rating field for Machine value.", description: "Creatures with the Machine Trait are partly or wholly inorganic. They do not breathe, are immune to vacuum, extreme cold, and mind-influencing psychic effects, and their Armour Points also protect against fire. Record the Machine value in the item's rating field to represent the Armour Points granted to all locations.", category: "trait" },
  { id: "multiple-arms", name: "Multiple Arms", prerequisites: "", benefit: "Gains +10 Toughness, +10 to climbing and swimming style Strength tests, and can make two attacks with Multiple Attack.", description: "This creature has more than one pair of arms. It gains +10 Toughness, a +10 bonus on Strength Tests involving movement such as Climb and Swim, and may use the Multiple Attack action to make two attacks on its turn.", category: "trait" },
  { id: "natural-armour", name: "Natural Armour", prerequisites: "", benefit: "Has built-in Armour Points on all locations; use the rating field for AP value.", description: "A thick hide, shell, or exoskeleton grants protection across the creature's body. Record the Armour value in the item's rating field to show how many Armour Points it gains on all locations.", category: "trait" },
  { id: "natural-weapons", name: "Natural Weapons", prerequisites: "", benefit: "Counts as armed, cannot be disarmed, and deals 1d10 + Strength Bonus Primitive damage.", description: "Claws, fangs, tusks, spines, or similar natural weapons count as an armed attack. The creature may attack with them using Weapon Skill, deals 1d10 plus Strength Bonus Damage, cannot normally be disarmed, and the attacks always count as Primitive. Natural weapons cannot be used to Parry unless a separate rule allows it.", category: "trait" },
  { id: "improved-natural-weapons", name: "Improved Natural Weapons", prerequisites: "", benefit: "Natural Weapons no longer count as Primitive.", description: "Some creatures have teeth, claws, or talons of exceptional lethality. Their Natural Weapons no longer count as Primitive.", category: "trait" },
  { id: "phase", name: "Phase", prerequisites: "", benefit: "Can switch into an insubstantial state as a Half Action and otherwise functions like Incorporeal, with extra limits against certain barriers.", description: "A phased creature can make its body insubstantial as a Half Action, functioning like an Incorporeal entity while phased. It may return to solidity with another Half Action. Even in this state, it cannot cross psychically charged barriers, holy wards, Geller Fields, Void Shields, or other effects that disrupt the Warp or local space.", category: "trait" },
  { id: "quadruped", name: "Quadruped", prerequisites: "", benefit: "Uses doubled Agility Bonus for movement, with extra multipliers for additional leg pairs.", description: "Quadrupeds cover ground much faster than bipeds. Double the creature's Agility Bonus to determine movement. If it has more than four legs, increase the multiplier by 1 for each extra pair of legs.", category: "trait" },
  { id: "regeneration", name: "Regeneration", prerequisites: "", benefit: "At the start of each turn, tests Toughness to heal 1 point of damage.", description: "A creature with this Trait recovers from injury at supernatural speed. At the start of each of its turns, it may test Toughness to remove 1 point of Damage. Once the creature is slain, it loses the benefit of this Trait.", category: "trait" },
  { id: "size", name: "Size", prerequisites: "", benefit: "Alters movement and how easy the creature is to hit; use notes or rating to record categories such as Miniscule, Puny, Scrawny, Hulking, Enormous, or Massive.", description: "This Trait records a creature's scale and bulk. Size modifies movement and affects how easy it is to strike the creature in combat. Use the item's rating or notes field to record the relevant size category and apply the appropriate movement and attack modifiers.", category: "trait" },
  { id: "sonar-sense", name: "Sonar Sense", prerequisites: "", benefit: "Perceives solid objects within 30 metres by sound; others may notice the emitted keening with Awareness.", description: "The creature reads its surroundings by emitting a sound frequency and interpreting the returning echoes. It can locate solid objects within 30 metres, and creatures within range may detect the strange sound with a Difficult (-10) Awareness Test.", category: "trait" },
  { id: "soul-bound", name: "Soul-Bound", prerequisites: "", benefit: "May roll an extra die on Perils of the Warp and keep the preferred result, but carries a lasting spiritual cost.", description: "The creature's soul is bound to a higher power or patron, which grants a measure of protection. A soul-bound psyker rolls an additional d10 when forced to roll on Perils of the Warp and may discard one of the results. Becoming soul-bound also imposes a lasting cost, such as Insanity, blindness, a permanent Characteristic loss, or mutation, depending on the nature of the binding.", category: "trait" },
  { id: "strange-physiology", name: "Strange Physiology", prerequisites: "", benefit: "All hits count as Body hits and death occurs when damage equals or exceeds Wounds.", description: "The creature's anatomy is so unusual that normal hit location assumptions break down. Treat all hits as Body hits, and the creature dies when accumulated Damage equals or exceeds its Wounds.", category: "trait" },
  { id: "sturdy", name: "Sturdy", prerequisites: "", benefit: "Gains +20 to resist grapples and Takedown.", description: "Sturdy creatures are difficult to drag down or throw off balance. They gain a +20 bonus on Tests made to resist grappling and the Takedown talent.", category: "trait" },
  { id: "stuff-of-nightmares", name: "Stuff of Nightmares", prerequisites: "", benefit: "Ignores many hazards and most critical effects unless the attack is psychic, holy, or force-based.", description: "Some Warp entities are so powerful that ordinary trauma barely registers. They are immune to poison, disease, suffocation, most environmental hazards, bleeding, stunning, and any Critical Effect short of total destruction, unless the result is caused by a psychic power, force weapon, or holy attack.", category: "trait" },
  { id: "toxic", name: "Toxic", prerequisites: "", benefit: "Exposes victims to poison through weapons, touch, or proximity, usually forcing a Toughness test.", description: "A creature with this Trait is venomous, poisonous, or emits toxic contamination. Victims struck by its natural weapons, touching it, or exposed to its fumes must usually make a Toughness Test or suffer poison. Typical Toxic effects deal 1d10 Damage that ignores Armour, though individual creatures may vary.", category: "trait" },
  { id: "unnatural-agility", name: "Unnatural Agility", prerequisites: "", benefit: "Increases the Agility Bonus multiplier by 1 for Opposed Tests and derived effects that use bonus multipliers.", description: "This creature's Agility is beyond the human norm. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test. Movement is still based on the unmodified Agility Bonus unless another rule states otherwise.", category: "trait" },
  { id: "unnatural-ballistic-skill", name: "Unnatural Ballistic Skill", prerequisites: "", benefit: "Increases the Ballistic Skill Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Ballistic Skill is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-fellowship", name: "Unnatural Fellowship", prerequisites: "", benefit: "Increases the Fellowship Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Fellowship is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-intelligence", name: "Unnatural Intelligence", prerequisites: "", benefit: "Increases the Intelligence Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Intelligence is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-perception", name: "Unnatural Perception", prerequisites: "", benefit: "Increases the Perception Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Perception is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-senses", name: "Unnatural Senses", prerequisites: "", benefit: "Perceives its surroundings through unusual organs or methods within the listed range.", description: "A creature with this Trait can detect its surroundings using alien or non-standard sensory organs. Record the effective range in the item's rating or notes field.", category: "trait" },
  { id: "unnatural-speed", name: "Unnatural Speed", prerequisites: "", benefit: "Doubles Agility Bonus for movement after other movement modifiers are applied.", description: "The creature moves with incredible quickness. For movement purposes, double its Agility Bonus after applying size and other movement modifiers.", category: "trait" },
  { id: "unnatural-strength", name: "Unnatural Strength", prerequisites: "", benefit: "Increases the Strength Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Strength is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-toughness", name: "Unnatural Toughness", prerequisites: "", benefit: "Increases the Toughness Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Toughness is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-weapon-skill", name: "Unnatural Weapon Skill", prerequisites: "", benefit: "Increases the Weapon Skill Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Weapon Skill is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "unnatural-willpower", name: "Unnatural Willpower", prerequisites: "", benefit: "Increases the Willpower Bonus multiplier by 1 for Opposed Tests and related effects.", description: "This creature's Willpower is unnaturally potent. Each time this Trait is taken for the same Characteristic, increase the Characteristic Bonus multiplier by 1. During Opposed Characteristic Tests, add the multiplier to Degrees of Success on a successful Test.", category: "trait" },
  { id: "warp-instability", name: "Warp Instability", prerequisites: "", benefit: "Must keep inflicting harm or horror after being damaged or begin unravelling back into the Warp.", description: "Most Warp entities struggle to remain anchored in reality. If a creature with this Trait takes Damage and does not inflict Damage or Insanity Points on another creature by the end of its next turn, it must make a Willpower Test. On a failure, it takes 1 Damage plus 1 additional Damage per Degree of Failure; if this equals or exceeds its Wounds, it is banished back into the Warp.", category: "trait" },
  { id: "warp-weapon", name: "Warp Weapon", prerequisites: "", benefit: "Natural attacks ignore normal armour and cover unless the protection is holy, psychoactive, or similarly supernatural.", description: "The creature's weapons are partially unreal and slide through mundane protection. Natural weapons and attacks made by a creature with this Trait ignore normal physical armour unless that protection is holy, psychoactive, or otherwise specifically resistant to Warp-tainted assault. Force fields still protect normally.", category: "trait" }
];

function slugifyTalentPart(value) {
  return String(value ?? "").trim().toLowerCase().replace(/["']/g, "").replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function expandGroupedTalent(definition) {
  const groups = TALENT_GROUPS[definition.groupKey] ?? [];
  return groups.map((groupName) => ({
    ...definition,
    id: `${definition.id}/${slugifyTalentPart(groupName)}`,
    baseId: definition.id,
    groupName,
    fullName: `${definition.name} (${groupName})`,
    benefit: definition.benefit.replace(/the chosen skill/g, groupName).replace(/the chosen group/g, groupName).replace(/the chosen/g, groupName),
    description: (definition.description ?? definition.benefit).replace(/the chosen skill/g, groupName).replace(/the chosen group/g, groupName).replace(/the chosen/g, groupName)
  }));
}

function buildTalentRegistry() {
  const expanded = [];
  for (const definition of [...BASE_TALENT_DEFINITIONS, ...TRAIT_DEFINITIONS]) {
    expanded.push(definition);
    if (definition.groupKey) expanded.push(...expandGroupedTalent(definition));
  }

  return expanded.reduce((registry, definition) => {
    registry[definition.id] = Object.freeze({ ...definition, fullName: definition.fullName ?? definition.name, description: definition.description ?? definition.benefit ?? "" });
    return registry;
  }, {});
}

export const ROGUE_TRADER_TALENTS = Object.freeze(buildTalentRegistry());
export function getRogueTraderTalentDefinition(talentId) { return ROGUE_TRADER_TALENTS[talentId] ?? null; }
export function listRogueTraderTalents() { return Object.values(ROGUE_TRADER_TALENTS); }

export function buildTalentItemData(talentId, overrides = {}) {
  const definition = getRogueTraderTalentDefinition(talentId);
  if (!definition) return null;

  return {
    name: overrides.name ?? definition.fullName,
    type: "talent",
    system: {
      category: overrides.category ?? definition.category ?? "talent",
      rating: overrides.rating ?? "",
      prerequisites: overrides.prerequisites ?? definition.prerequisites ?? "",
      benefit: overrides.benefit ?? definition.benefit ?? "",
      description: overrides.description ?? definition.description ?? definition.benefit ?? ""
    }
  };
}

export class RogueTraderTalentSheet extends HandlebarsApplicationMixin(ItemSheetV2) {
  static register() {
    Items.registerSheet("roguetrader", RogueTraderTalentSheet, { types: ["talent"], makeDefault: true });
  }

  static DEFAULT_OPTIONS = foundry.utils.mergeObject(super.DEFAULT_OPTIONS, {
    classes: ["roguetrader", "sheet", "item", "talent"],
    position: {
      width: 560,
      height: 620
    },
    window: {
      resizable: true
    },
    form: {
      submitOnChange: true,
      closeOnSubmit: false
    }
  });

  static PARTS = {
    sheet: {
      template: "systems/roguetrader/templates/items/talent.hbs",
      root: true
    }
  };

  async _prepareContext(options) {
    const context = await super._prepareContext(options);
    context.item = this.item;
    context.system = this.item.system;
    context.talentTypes = TALENT_TYPE_LABELS;
    context.ratingOptions = TALENT_RATING_OPTIONS;
    context.careerOptions = TALENT_CAREER_OPTIONS;
    context.isSpecialAbility = String(this.item.system?.category ?? "").trim() === "specialAbility";
    context.isArchMilitantSpecialAbility = context.isSpecialAbility && String(this.item.system?.rating ?? "").trim() === "archMilitant";
    context.weaponMasterOptions = TALENT_WEAPON_MASTER_OPTIONS;
    context.talentGroups = TALENT_GROUPS;
    context.talentRegistry = ROGUE_TRADER_TALENTS;
    return context;
  }
}




